    /// to be available; if `ExtractionConfig.ocr` is `None` the extractor
    /// falls back to `TesseractConfig::default()`. Per-image failures degrade
    /// gracefully (the image is returned without OCR text rather than failing
    /// the whole extraction). Default: `false`.
    public let ocrInlineImages: Bool
    /// Extract AcroForm and XFA form fields into `ExtractedDocument.form_fields`.
    ///
    /// When `true` (default), reads the document's interactive form structure
    /// (field names, types, values, widget geometry). Cheap and strictly
    /// additive — non-form PDFs simply yield an empty list. Set to `false` to
    /// skip the form pass entirely.
    public let extractFormFields: Bool
    /// Reorder extracted text by layout-detected reading order.
    ///
    /// When `true`, projects text spans onto layout-detected regions, performs
    /// column detection, and emits spans in natural reading order (important
    /// for multi-column academic PDFs). Requires the `layout-detection`
    /// feature; has no effect without it. Defaults to `false`.
    public let readingOrder: Bool
    public init(extractImages: Bool, extractTables: Bool, passwords: [String]? = nil, extractMetadata: Bool, hierarchy: HierarchyConfig? = nil, extractAnnotations: Bool, topMarginFraction: Float? = nil, bottomMarginFraction: Float? = nil, allowSingleColumnTables: Bool, ocrInlineImages: Bool, extractFormFields: Bool, readingOrder: Bool) {
        self.extractImages = extractImages
        self.extractTables = extractTables
        self.passwords = passwords
        self.extractMetadata = extractMetadata
        self.hierarchy = hierarchy
        self.extractAnnotations = extractAnnotations
        self.topMarginFraction = topMarginFraction
        self.bottomMarginFraction = bottomMarginFraction
        self.allowSingleColumnTables = allowSingleColumnTables
        self.ocrInlineImages = ocrInlineImages
        self.extractFormFields = extractFormFields
        self.readingOrder = readingOrder
    }
    private enum CodingKeys: String, CodingKey {
        case extractImages = "extract_images"
        case extractTables = "extract_tables"
        case passwords = "passwords"
        case extractMetadata = "extract_metadata"
        case hierarchy = "hierarchy"
        case extractAnnotations = "extract_annotations"
        case topMarginFraction = "top_margin_fraction"
        case bottomMarginFraction = "bottom_margin_fraction"
        case allowSingleColumnTables = "allow_single_column_tables"
