    }

    func intoRust() throws -> RustBridge.Formula {
        let data = try JSONEncoder().encode(self)
        let json = String(data: data, encoding: .utf8) ?? "{}"
        return try RustBridge.formulaFromJson(json)
    }
}

/// Code-format metadata: the structural chunks produced by tree-sitter parsing.
///
/// Wrapped by [`FormatMetadata::Code`]. Kept as a named struct (rather than an inline
/// enum-variant body) so serde can tag it under internal tagging and utoipa can emit a
/// referenceable `CodeMetadata` component in the OpenAPI schema.
public struct CodeMetadata: Codable, Sendable, Hashable {
    /// Structural code chunks (function/class/module boundaries).
    public let chunks: [CodeChunkInfo]
    public init(chunks: [CodeChunkInfo]) {
        self.chunks = chunks
    }
    private enum CodingKeys: String, CodingKey {
        case chunks = "chunks"
    }
    public init(from decoder: any Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.chunks = try container.decodeIfPresent([CodeChunkInfo].self, forKey: .chunks) ?? []
    }
}

// MARK: - Internal FFI conversions for CodeMetadata
internal extension CodeMetadata {
    init(_ rb: RustBridge.CodeMetadataRef) throws {
        self.chunks = try rb.chunks().map { (s: RustStringRef) -> CodeChunkInfo in let d = s.as_str().toString().data(using: .utf8) ?? Data(); return try JSONDecoder().decode(CodeChunkInfo.self, from: d) }
    }

    func intoRust() throws -> RustBridge.CodeMetadata {
        let __chunks = RustVec<RustBridge.CodeChunkInfo>()
        for __elem in self.chunks { __chunks.push(value: try __elem.intoRust()) }
        return RustBridge.CodeMetadata(__chunks)
