/// The content changes that make up a single revision.
///
/// For insertions and deletions the `content` field carries the added/removed
/// lines as `DiffLine::Added` / `DiffLine::Removed` entries. For format
/// changes, `property_changes` carries normalized before/after formatting
/// values when the source document exposes them.
public struct RevisionDelta: Codable, Sendable, Hashable {
    /// Line-level content changes for this revision.
    public let content: [DiffLine]
    /// Cell-level table changes for this revision.
    public let tableChanges: [CellChange]
    /// Formatting or metadata property changes for this revision.
    public let propertyChanges: [PropertyChange]
    public init(content: [DiffLine], tableChanges: [CellChange], propertyChanges: [PropertyChange]) {
        self.content = content
        self.tableChanges = tableChanges
        self.propertyChanges = propertyChanges
    }
    private enum CodingKeys: String, CodingKey {
        case content = "content"
        case tableChanges = "table_changes"
        case propertyChanges = "property_changes"
    }
    public init(from decoder: any Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.content = try container.decodeIfPresent([DiffLine].self, forKey: .content) ?? []
        self.tableChanges = try container.decodeIfPresent([CellChange].self, forKey: .tableChanges) ?? []
        self.propertyChanges = try container.decodeIfPresent([PropertyChange].self, forKey: .propertyChanges) ?? []
    }
}

// MARK: - Internal FFI conversions for RevisionDelta
internal extension RevisionDelta {
    init(_ rb: RustBridge.RevisionDeltaRef) throws {
        self.content = try rb.content().map { (s: RustStringRef) -> DiffLine in let d = s.as_str().toString().data(using: .utf8) ?? Data(); return try JSONDecoder().decode(DiffLine.self, from: d) }
        self.tableChanges = try rb.tableChanges().map { (s: RustStringRef) -> CellChange in let d = s.as_str().toString().data(using: .utf8) ?? Data(); return try JSONDecoder().decode(CellChange.self, from: d) }
        self.propertyChanges = try rb.propertyChanges().map { (s: RustStringRef) -> PropertyChange in let d = s.as_str().toString().data(using: .utf8) ?? Data(); return try JSONDecoder().decode(PropertyChange.self, from: d) }
    }

    func intoRust() throws -> RustBridge.RevisionDelta {
        let __content = RustVec<RustBridge.DiffLine>()
        for __elem in self.content { __content.push(value: try __elem.intoRust()) }
        let __tableChanges = RustVec<RustBridge.CellChange>()
        for __elem in self.tableChanges { __tableChanges.push(value: try __elem.intoRust()) }
        let __propertyChanges = RustVec<RustBridge.PropertyChange>()
        for __elem in self.propertyChanges { __propertyChanges.push(value: try __elem.intoRust()) }
        return RustBridge.RevisionDelta(__content, __tableChanges, __propertyChanges)
    }
}

