/// Configuration for document chunking and analysis heuristics.
///
/// Every threshold is a public field so callers can override any subset via
/// struct-update syntax: `HeuristicsConfig { text_layer_threshold: 0.5, ..Default::default() }`.
public struct HeuristicsConfig: Codable, Sendable, Hashable {
    /// Enable PDF text-layer detection heuristics.
    ///
    /// When `true`, PDFs with a substantial text layer will skip chunking.
    /// Default: `true`.
    public let enablePdfTextHeuristics: Bool
    /// Minimum fraction of pages that must have text to skip chunking.
    ///
    /// Range `0.0..=1.0`. Default: `0.7` (70 % of pages).
    public let textLayerThreshold: Float
    /// File size threshold in bytes for considering chunking.
    ///
    /// Files smaller than this are processed without chunking.
    /// Default: 10 MiB (10 × 1 024 × 1 024).
    public let fileSizeThresholdBytes: UInt64
    /// Page count threshold for considering chunking.
    ///
    /// Documents with fewer pages are processed without chunking.
    /// Default: 50.
    public let pageCountThreshold: UInt32
    /// Target number of pages per chunk for optimal parallel processing.
    ///
    /// Default: 10.
    public let targetPagesPerChunk: UInt32
    /// Hard cap on pages per chunk.
    ///
    /// No chunk will exceed this limit. Must be ≥ `target_pages_per_chunk`.
    /// Default: 25.
    public let maxPagesPerChunk: UInt32
    /// File size threshold for disk-based processing.
    ///
    /// Files larger than this are buffered to disk to prevent OOM.
    /// Default: 50 MiB (50 × 1 024 × 1 024).
    public let diskProcessingThresholdBytes: UInt64
    /// Minimum characters per page to consider a page as having text.
    ///
    /// Default: 50.
    public let minCharsPerPage: UInt32
    /// Maximum sheet count allowed in an XLSX workbook.
    ///
    /// Workbooks beyond this are rejected pre-extraction to avoid OOM /
    /// abusive billing inflation. Default: 200.
    public let maxXlsxSheetCount: UInt32
    /// Maximum cell count (sheets × rows × columns approximation) in an XLSX workbook.
    ///
    /// Default: 5 000 000 (≈ 200 sheets × 25 k cells).
    public let maxXlsxWorkbookCells: UInt64
    /// Maximum number of OLE-embedded objects extractable from a single PPTX or DOCX.
    ///
    /// Protects against zip-bomb-style nested-document abuse. Default: 50.
    public let maxPptxEmbeddedCount: UInt32
    public init(enablePdfTextHeuristics: Bool, textLayerThreshold: Float, fileSizeThresholdBytes: UInt64, pageCountThreshold: UInt32, targetPagesPerChunk: UInt32, maxPagesPerChunk: UInt32, diskProcessingThresholdBytes: UInt64, minCharsPerPage: UInt32, maxXlsxSheetCount: UInt32, maxXlsxWorkbookCells: UInt64, maxPptxEmbeddedCount: UInt32) {
        self.enablePdfTextHeuristics = enablePdfTextHeuristics
        self.textLayerThreshold = textLayerThreshold
        self.fileSizeThresholdBytes = fileSizeThresholdBytes
        self.pageCountThreshold = pageCountThreshold
        self.targetPagesPerChunk = targetPagesPerChunk
        self.maxPagesPerChunk = maxPagesPerChunk
        self.diskProcessingThresholdBytes = diskProcessingThresholdBytes
        self.minCharsPerPage = minCharsPerPage
        self.maxXlsxSheetCount = maxXlsxSheetCount
        self.maxXlsxWorkbookCells = maxXlsxWorkbookCells
        self.maxPptxEmbeddedCount = maxPptxEmbeddedCount
    }
    private enum CodingKeys: String, CodingKey {
        case enablePdfTextHeuristics = "enable_pdf_text_heuristics"
        case textLayerThreshold = "text_layer_threshold"
        case fileSizeThresholdBytes = "file_size_threshold_bytes"
        case pageCountThreshold = "page_count_threshold"
        case targetPagesPerChunk = "target_pages_per_chunk"
        case maxPagesPerChunk = "max_pages_per_chunk"
        case diskProcessingThresholdBytes = "disk_processing_threshold_bytes"
        case minCharsPerPage = "min_chars_per_page"
        case maxXlsxSheetCount = "max_xlsx_sheet_count"
        case maxXlsxWorkbookCells = "max_xlsx_workbook_cells"
        case maxPptxEmbeddedCount = "max_pptx_embedded_count"
    }
    public init(from decoder: any Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.enablePdfTextHeuristics = try container.decodeIfPresent(Bool.self, forKey: .enablePdfTextHeuristics) ?? true
        self.textLayerThreshold = try container.decodeIfPresent(Float.self, forKey: .textLayerThreshold) ?? 0.7
        self.fileSizeThresholdBytes = try container.decodeIfPresent(UInt64.self, forKey: .fileSizeThresholdBytes) ?? 10485760
        self.pageCountThreshold = try container.decodeIfPresent(UInt32.self, forKey: .pageCountThreshold) ?? 50
        self.targetPagesPerChunk = try container.decodeIfPresent(UInt32.self, forKey: .targetPagesPerChunk) ?? 10
        self.maxPagesPerChunk = try container.decodeIfPresent(UInt32.self, forKey: .maxPagesPerChunk) ?? 25
        self.diskProcessingThresholdBytes = try container.decodeIfPresent(UInt64.self, forKey: .diskProcessingThresholdBytes) ?? 52428800
        self.minCharsPerPage = try container.decodeIfPresent(UInt32.self, forKey: .minCharsPerPage) ?? 50
        self.maxXlsxSheetCount = try container.decodeIfPresent(UInt32.self, forKey: .maxXlsxSheetCount) ?? 200
        self.maxXlsxWorkbookCells = try container.decodeIfPresent(UInt64.self, forKey: .maxXlsxWorkbookCells) ?? 5000000
        self.maxPptxEmbeddedCount = try container.decodeIfPresent(UInt32.self, forKey: .maxPptxEmbeddedCount) ?? 50
    }
    // MARK: - Instance Methods
    public func validate() throws  {
