        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.urls = try container.decodeIfPresent([SitemapUrl].self, forKey: .urls) ?? []
    }
}

// MARK: - Internal FFI conversions for MapResult
internal extension MapResult {
    init(_ rb: RustBridge.MapResultRef) throws {
        self.urls = try rb.urls().map { (s: RustStringRef) -> SitemapUrl in let d = s.as_str().toString().data(using: .utf8) ?? Data(); return try JSONDecoder().decode(SitemapUrl.self, from: d) }
    }

    func intoRust() throws -> RustBridge.MapResult {
        let __urls = RustVec<RustBridge.SitemapUrl>()
        for __elem in self.urls { __urls.push(value: try __elem.intoRust()) }
        return RustBridge.MapResult(__urls)
    }
}

