        self.denyPrivate = try container.decodeIfPresent(Bool.self, forKey: .denyPrivate) ?? true
        self.maxRedirects = try container.decodeIfPresent(UInt8.self, forKey: .maxRedirects) ?? 5
    }
}

// MARK: - Internal FFI conversions for SsrfPolicy
