        case "custom":
            self = .custom(modelId: try container.decode(String.self, forKey: .modelId), modelFile: try container.decodeIfPresent(String.self, forKey: .modelFile), additionalFiles: try container.decode([String].self, forKey: .additionalFiles), maxLength: try container.decodeIfPresent(Int64.self, forKey: .maxLength))
