/// Policy controlling when VLM (Vision Language Model) OCR is used as a fallback.
///
/// This knob is syntactic sugar over the explicit [`OcrPipelineConfig`] stage
/// ordering. When `vlm_fallback` is set and `pipeline` is `None`, an equivalent
/// pipeline is synthesised at extraction time:
///
/// - [`VlmFallbackPolicy::Disabled`] — no synthesis; single-backend mode (default).
/// - [`VlmFallbackPolicy::OnLowQuality`] — tries the classical backend first; if the
///   result scores below `quality_threshold`, tries VLM.
/// - [`VlmFallbackPolicy::Always`] — skips the classical backend and sends every page
///   to the VLM.
///
/// When [`OcrConfig::pipeline`] is explicitly set, `vlm_fallback` is ignored — the
/// explicit pipeline takes precedence.
///
/// # Errors
///
/// Both `OnLowQuality` and `Always` require [`OcrConfig::vlm_config`] to be `Some`.
/// Constructing an [`OcrConfig`] with one of these policies but no `vlm_config` is
/// detected by `OcrConfig::validate` and will surface as a
/// `Validation` error at extraction time, not a panic.
///
/// # Example
///
/// ```rust
/// use xberg::{OcrConfig, VlmFallbackPolicy, LlmConfig};
///
/// let config = OcrConfig {
///     vlm_fallback: VlmFallbackPolicy::OnLowQuality { quality_threshold: 0.6 },
///     vlm_config: Some(LlmConfig {
///         model: "openai/gpt-4o-mini".to_string(),
///         ..Default::default()
///     }),
///     ..Default::default()
/// };
///
/// // Threshold calibration is deferred to the Stage 0 benchmark harness.
/// assert!(matches!(config.vlm_fallback, VlmFallbackPolicy::OnLowQuality { .. }));
/// ```
public enum VlmFallbackPolicy: Codable, Sendable, Hashable {
    /// No VLM fallback (default). Behaves identically to the pre-policy single-backend mode.
    case disabled
    /// Try the classical OCR backend first. If the quality score is below
    /// `quality_threshold`, send the page to the VLM.
    ///
    /// `quality_threshold` is in the `[0.0, 1.0]` range produced by
    /// `calculate_quality_score`. A value of `0.5` is a
    /// reasonable starting point; calibrate with the Stage 0 benchmark harness.
    case onLowQuality(qualityThreshold: Double)
    /// Skip the classical OCR backend entirely. Every page is sent to the VLM.
    case always

    private enum CodingKeys: String, CodingKey {
        case mode

        case qualityThreshold = "quality_threshold"    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let type = try container.decode(String.self, forKey: .mode)
        switch type {
        case "disabled":
            self = .disabled
        case "on_low_quality":
            self = .onLowQuality(qualityThreshold: try container.decode(Double.self, forKey: .qualityThreshold))
        case "always":
            self = .always
        default:
            throw DecodingError.dataCorruptedError(
                forKey: .mode,
                in: container,
                debugDescription: "Unknown VlmFallbackPolicy type: \(type)"
            )
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .disabled:
            try container.encode("disabled", forKey: .mode)
        case .onLowQuality(let qualityThreshold):
            try container.encode("on_low_quality", forKey: .mode)
            try container.encode(qualityThreshold, forKey: .qualityThreshold)

        case .always:
            try container.encode("always", forKey: .mode)
        }
    }
}
extension VlmFallbackPolicy {
    func intoRust() throws -> RustBridge.VlmFallbackPolicy {
        let data = try JSONEncoder().encode(self)
        let json = String(data: data, encoding: .utf8) ?? "null"
        return try RustBridge.vlmFallbackPolicyFromJson(json)
    }
}

/// Controls how markdown tables are handled when they exceed the chunk size limit.
///
/// Only applies when `chunker_type` is `Markdown`.
///
/// # Variants
///
/// * `Split` - Default behavior: tables are split at row boundaries like any
///   other block element. Continuation chunks contain only data rows without
///   the header, which can break downstream consumers that need column context.
/// * `RepeatHeader` - Prepend the table header (header row + separator row) to
///   every continuation chunk that contains data rows from the same table.
///   Adds a small amount of duplicate text but ensures each chunk is
///   self-contained for extraction, search, and LLM consumption.
public enum TableChunkingMode: String, Codable, Sendable, Hashable {
    /// Split tables at row boundaries (default). Continuation chunks have no header.
    case split
    /// Prepend the table header to every chunk that continues a split table.
    case repeatHeader = "repeat_header"
}
extension TableChunkingMode {
    func intoRust() throws -> RustBridge.TableChunkingMode {
        let data = try JSONEncoder().encode(self)
        let json = String(data: data, encoding: .utf8) ?? "null"
        return try RustBridge.tableChunkingModeFromJson(json)
    }
}

/// Type of text chunker to use.
///
/// # Variants
///
/// * `Text` - Generic text splitter, splits on whitespace and punctuation
/// * `Markdown` - Markdown-aware splitter, preserves formatting and structure
/// * `Yaml` - YAML-aware splitter, creates one chunk per top-level key
/// * `Semantic` - Topic-aware chunker. With an `EmbeddingConfig`, splits at
///   embedding-based topic shifts tuned by `topic_threshold` (default 0.75,
///   lower = more splits). Without an embedding, falls back to a
///   structural-boundary heuristic (ALL-CAPS headers, numbered sections,
///   blank-line paragraphs) and merges groups into chunks capped at
///   `max_characters` (default 1000). `topic_threshold` has no effect in the
///   fallback path. For best results, pair with an embedding model.
public enum ChunkerType: String, Codable, Sendable, Hashable {
    /// Generic whitespace- and punctuation-aware text splitter (default).
    case text
    /// Markdown-aware splitter that preserves heading and code-block boundaries.
    case markdown
    /// YAML-aware splitter that creates one chunk per top-level key.
    case yaml
    /// Topic-aware chunker that splits at embedding-based topic shifts.
    case semantic
}
extension ChunkerType {
    func intoRust() throws -> RustBridge.ChunkerType {
        let data = try JSONEncoder().encode(self)
        let json = String(data: data, encoding: .utf8) ?? "null"
        return try RustBridge.chunkerTypeFromJson(json)
    }
}

/// How chunk size is measured.
///
/// Defaults to `Characters` (Unicode character count). When using token-based sizing,
/// chunks are sized by token count according to the specified tokenizer.
///
/// Token-based sizing uses HuggingFace tokenizers loaded at runtime, or a tokenizer
/// backend you register yourself. Any tokenizer available on HuggingFace Hub can be
/// used, including OpenAI-compatible tokenizers (e.g., `Xenova/gpt-4o`,
/// `Xenova/cl100k_base`). To size chunks with your own tokenizer instead (llama.cpp/GGUF
/// vocabularies, SentencePiece models, custom vocabs), register a `TokenizerBackend`
/// with `register_tokenizer_backend` and set `model` to the registered name.
public enum ChunkSizing: Codable, Sendable, Hashable {
    /// Size measured in Unicode characters (default).
    case characters
    /// Size measured in tokens from a HuggingFace tokenizer or a registered
    /// tokenizer backend.
    case tokenizer(model: String, cacheDir: URL?)

    private enum CodingKeys: String, CodingKey {
        case type

        case cacheDir = "cache_dir"
        case model    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let type = try container.decode(String.self, forKey: .type)
        switch type {
        case "characters":
            self = .characters
        case "tokenizer":
            self = .tokenizer(model: try container.decode(String.self, forKey: .model), cacheDir: try container.decodeIfPresent(URL.self, forKey: .cacheDir))
        default:
            throw DecodingError.dataCorruptedError(
                forKey: .type,
                in: container,
                debugDescription: "Unknown ChunkSizing type: \(type)"
            )
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .characters:
            try container.encode("characters", forKey: .type)
        case .tokenizer(let model, let cacheDir):
            try container.encode("tokenizer", forKey: .type)
            try container.encode(model, forKey: .model)
            try container.encodeIfPresent(cacheDir, forKey: .cacheDir)

        }
    }
}
extension ChunkSizing {
    func intoRust() throws -> RustBridge.ChunkSizing {
        let data = try JSONEncoder().encode(self)
        let json = String(data: data, encoding: .utf8) ?? "null"
        return try RustBridge.chunkSizingFromJson(json)
    }
}

/// Embedding model types supported by Xberg.
public enum EmbeddingModelType: Codable, Sendable, Hashable {
    /// Use a preset model configuration (recommended)
    case preset(name: String)
    /// Use a custom ONNX model from HuggingFace
    case custom(modelId: String, dimensions: UInt)
    /// Provider-hosted embedding model via liter-llm.
    ///
    /// Uses the model specified in the nested `LlmConfig` (e.g.,
