public enum RerankerHead: String, Codable, Sendable, Hashable {
    /// Single-logit cross-encoder head (sigmoid applied by the caller).
    case crossEncoder = "cross_encoder"
    /// Qwen3 generative-reranker head (softmax over yes/no token logits).
    case qwen3Generative = "qwen3_generative"
}
