        let type = try container.decode(String.self, forKey: .type)
        switch type {
        case "SmallFile":
            self = .smallFile(sizeBytes: try container.decode(UInt64.self, forKey: .sizeBytes), thresholdBytes: try container.decode(UInt64.self, forKey: .thresholdBytes))
        case "FewPages":
            self = .fewPages(pageCount: try container.decode(UInt32.self, forKey: .pageCount), threshold: try container.decode(UInt32.self, forKey: .threshold))
        case "TextLayerDetected":
            self = .textLayerDetected(textCoverage: try container.decode(Float.self, forKey: .textCoverage), avgCharsPerPage: try container.decode(UInt32.self, forKey: .avgCharsPerPage))
        case "FormatNotChunkable":
            self = .formatNotChunkable(mimeType: try container.decode(String.self, forKey: .mimeType))
        case "ChunkingDisabled":
            self = .chunkingDisabled
        case "FastTextExtraction":
            self = .fastTextExtraction
        default:
            throw DecodingError.dataCorruptedError(
                forKey: .type,
                in: container,
                debugDescription: "Unknown NoChunkingReason type: \(type)"
            )
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .smallFile(let sizeBytes, let thresholdBytes):
            try container.encode("SmallFile", forKey: .type)
            try container.encode(sizeBytes, forKey: .sizeBytes)
            try container.encode(thresholdBytes, forKey: .thresholdBytes)

        case .fewPages(let pageCount, let threshold):
            try container.encode("FewPages", forKey: .type)
            try container.encode(pageCount, forKey: .pageCount)
            try container.encode(threshold, forKey: .threshold)

        case .textLayerDetected(let textCoverage, let avgCharsPerPage):
            try container.encode("TextLayerDetected", forKey: .type)
            try container.encode(textCoverage, forKey: .textCoverage)
            try container.encode(avgCharsPerPage, forKey: .avgCharsPerPage)

        case .formatNotChunkable(let mimeType):
            try container.encode("FormatNotChunkable", forKey: .type)
            try container.encode(mimeType, forKey: .mimeType)

        case .chunkingDisabled:
            try container.encode("ChunkingDisabled", forKey: .type)
        case .fastTextExtraction:
