    /// A JavaScript file.
    case script
    /// An archive file (ZIP, TAR, etc.).
    case archive
    /// A data file (JSON, XML, CSV, etc.).
    case data
    /// An unrecognized asset type.
    case other
}
extension AssetCategory {
    func intoRust() throws -> RustBridge.AssetCategory {
        let data = try JSONEncoder().encode(self)
        let json = String(data: data, encoding: .utf8) ?? "null"
        return try RustBridge.assetCategoryFromJson(json)
    }
}

/// Main error type for all Xberg operations.
///
/// All errors in Xberg use this enum, which preserves error chains
/// and provides context for debugging.
///
/// # Variants
///
/// - `Io` - File system and I/O errors (always bubble up)
/// - `Parsing` - Document parsing errors (corrupt files, unsupported features)
/// - `Ocr` - OCR processing errors
/// - `Validation` - Input validation errors (invalid paths, config, parameters)
/// - `Cache` - Cache operation errors (non-fatal, can be ignored)
/// - `ImageProcessing` - Image manipulation errors
/// - `Serialization` - JSON/MessagePack serialization errors
/// - `MissingDependency` - Missing optional dependencies (tesseract, etc.)
/// - `Plugin` - Plugin-specific errors
/// - `LockPoisoned` - Mutex/RwLock poisoning (should not happen in normal operation)
/// - `UnsupportedFormat` - Unsupported MIME type or file format
/// - `Other` - Catch-all for uncommon errors
public enum XbergError: Swift.Error {
    /// A file system or I/O operation failed. These errors always bubble up unchanged.
    case io(message: String, field0: String)
    /// Document parsing failed (e.g. corrupt file, unsupported format feature).
    case parsing(message: String, source: String?)
    /// An OCR engine returned an error or produced unusable output.
    case ocr(message: String, source: String?)
    /// Invalid configuration or input parameters were supplied.
    case validation(message: String, source: String?)
    /// A cache read or write operation failed.
    case cache(message: String, source: String?)
    /// An image manipulation operation (resize, decode, DPI conversion) failed.
    case imageProcessing(message: String, source: String?)
    /// JSON or MessagePack serialization/deserialization failed.
    case serialization(message: String, source: String?)
    /// A required optional system dependency (e.g. `tesseract`) was not found.
    case missingDependency(message: String, field0: String)
    /// A registered plugin returned an error during extraction.
    case plugin(message: String, pluginName: String)
    /// An internal `Mutex` or `RwLock` was found in a poisoned state.
    case lockPoisoned(message: String, field0: String)
    /// The document's MIME type is not supported by any registered extractor.
    case unsupportedFormat(message: String, field0: String)
    /// The embedding model or embedding pipeline returned an error.
    case embedding(message: String, source: String?)
    /// The reranker model or reranking pipeline returned an error.
    ///
    /// Since v5.0.0.
    case reranking(message: String, source: String?)
    /// Audio/video transcription failed.
    case transcription(message: String, source: String?)
    /// The extraction operation exceeded the configured time limit.
    case timeout(message: String, elapsedMs: UInt64, limitMs: UInt64)
    /// The extraction was cancelled via a `CancellationToken`.
    case cancelled
    /// A security policy was violated (e.g. zip bomb, oversized archive).
    case security(message: String, source: String?)
    /// A catch-all for uncommon errors that do not fit another variant.
    case other(message: String, field0: String)
}

/// Errors that can occur during heuristics analysis.
public enum HeuristicsError: Swift.Error {
    /// Invalid configuration value.
    case configError(message: String, field0: String)
    /// PDF analysis step failed (only when `heuristics-pdf` feature is active).
    case pdfAnalysisError(message: String, field0: String)
    /// Synthetic case raised when a Rust serde unit-enum raw value cannot
    /// be mapped to a known Swift case during DTO unmarshaling.
    case validation(message: String, source: String)
}

/// Errors produced while loading or validating a preset file.
public enum LoadError: Swift.Error {
    /// The file is not valid JSON.
    case parse(message: String, path: String, source: String)
    /// The file parses as JSON but does not validate against the meta-schema.
    case schemaValidation(message: String, path: String, errors: String)
    /// The file validates but cannot be deserialized into [`Preset`].
    case deserialize(message: String, path: String, source: String)
    /// The preset's declared `id` does not match its file-system location.
    case idMismatch(message: String, path: String, declared: String, expected: String)
    /// The meta-schema itself failed to compile.
    case badMetaSchema(message: String, field0: String)
    /// A filesystem I/O error occurred while reading a preset directory.
    case io(message: String, field0: String)
    /// Synthetic case raised when a Rust serde unit-enum raw value cannot
    /// be mapped to a known Swift case during DTO unmarshaling.
    case validation(message: String, source: String)
}

/// Errors produced while resolving a preset against caller overrides.
public enum ResolveError: Swift.Error {
    /// A custom schema override was supplied but is not a JSON object.
    case schemaNotObject
    /// Synthetic case raised when a Rust serde unit-enum raw value cannot
    /// be mapped to a known Swift case during DTO unmarshaling.
    case validation(message: String, source: String)
}

// MARK: - JSON-String Convenience Overloads
// These overloads accept JSON-encoded config parameters and decode them automatically.
// Enables e2e tests to pass JSON strings directly without typed config construction.

/// Resolves a string argument as either a file path or literal UTF-8 content.
/// Searches: current working directory, ALEF_TEST_DOCUMENTS_DIR env var,
/// and ancestor `test_documents/` or `fixtures/` directories (up to 16 levels).
/// If no file is found, treats the string as UTF-8 content and returns its bytes.
private func _loadBytesFromPathOrUtf8(_ pathOrContent: String) throws -> [UInt8] {
    let fm = FileManager.default
    var roots: [String] = [fm.currentDirectoryPath]
    if let envRoot = ProcessInfo.processInfo.environment["ALEF_TEST_DOCUMENTS_DIR"] {
        roots.append(envRoot)
    }
    var walker = URL(fileURLWithPath: fm.currentDirectoryPath)
    for _ in 0..<16 {
        roots.append(walker.appendingPathComponent("test_documents").path)
        roots.append(walker.appendingPathComponent("fixtures").path)
        let parent = walker.deletingLastPathComponent()
        if parent.path == walker.path { break }
        walker = parent
    }
    let candidates = [pathOrContent] + roots.map { ($0 as NSString).appendingPathComponent(pathOrContent) }
    for path in candidates {
        if fm.fileExists(atPath: path), let data = try? Data(contentsOf: URL(fileURLWithPath: path)) {
            return [UInt8](data)
        }
    }
    return [UInt8](pathOrContent.utf8)
}

