// MARK: - Free-function Forwarders
// Re-export every public free function on the source Rust crate as a
// top-level `public func` on the host module so consumers do not need to
// `import RustBridge` directly. Forwarders take Swift-native parameter
// types and convert to the swift-bridge runtime types internally.

/// Extract content from a single bytes or URI input.
public func extract(input: ExtractInput, config: ExtractionConfig) async throws -> ExtractionResult {
    return try await Task.detached(priority: .userInitiated) {
        let result = try RustBridge.extract(input, config)
        return result
    }.value
}

/// Extract content from multiple bytes or URI inputs.
public func extractBatch(inputs: [ExtractInput], config: ExtractionConfig) async throws -> ExtractionResult {
    return try await Task.detached(priority: .userInitiated) {
        let _rb_inputs: RustVec<ExtractInput> = { let v = RustVec<ExtractInput>(); for x in inputs { v.push(value: x) }; return v }()
        let result = try RustBridge.extractBatch(_rb_inputs, config)
        return result
    }.value
}

/// Discover all pages and sitemaps reachable from `uri` without extracting document content.
///
/// Builds a [`crawlberg::CrawlEngine`] from `config.crawl`, calls
/// [`CrawlEngine::map`], and returns the set of discovered URLs as a
/// [`crawlberg::MapResult`] (re-exported as `MapResult`).
///
/// Use this when you need the URL inventory of a site before committing to
/// full document extraction — e.g. to build a crawl queue or validate scope.
///
/// # Errors
///
/// Returns `Validation` if the crawl configuration fails
/// validation or if the map operation itself fails.
public func mapUrl(uri: String, config: UrlExtractionConfig) async throws -> MapResult {
    return try await Task.detached(priority: .userInitiated) {
        let _rb_uri = RustString(uri)
        let _rb_obj = try RustBridge.mapUrl(_rb_uri, config)
        return try MapResult(_rb_obj)
    }.value
}

/// List all supported document formats.
///
/// Returns every file extension Xberg recognizes together with its
/// corresponding MIME type, derived from the central format registry.
/// Formats that have no registered file extension (such as source code,
/// which is detected dynamically) are not included.
///
/// The list is sorted alphabetically by file extension.
///
/// # Returns
///
/// A vector of [`SupportedFormat`] entries sorted by extension.
///
/// # Example
///
/// ```
/// use xberg::core::mime::list_supported_formats;
///
/// let formats = list_supported_formats();
/// assert!(!formats.is_empty());
/// assert!(formats.iter().any(|f| f.extension == "pdf"));
/// ```
public func listSupportedFormats() throws -> [SupportedFormat] {
    return try RustBridge.listSupportedFormats().map { ref in try SupportedFormat(ref) }
}
